// ElevenLabs Conversational AI post-call payload shape:
// { agent_id, conversation_id, call_sid?, transcript: [{role,message}], metadata, duration_seconds, ... }
// Our outbound dialer (WF5) adds extra top-level fields: { direction, org_id, caller, dialed }.
const raw = items[0].json.body || items[0].json;
const transcript = (raw.transcript || raw.conversation || []).map(t => `${t.role || t.speaker || '?'}: ${t.message || t.text || ''}`).join('\n');
const direction = raw.direction || (raw.metadata && raw.metadata.direction) || 'inbound';
const callerNumber = raw.caller || (raw.metadata && raw.metadata.caller) || raw.from || null;
const dialedNumber = raw.dialed || (raw.metadata && raw.metadata.dialed) || raw.to || null;
const orgId = raw.org_id || (raw.metadata && raw.metadata.org_id) || null;
const callSid = raw.call_sid || raw.conversation_id || null;
const durationSec = raw.duration_seconds || raw.call_duration_secs || 0;
if (!transcript || transcript.length < 4) { throw new Error('empty transcript — nothing to process'); }
return [{ json: { transcript, direction, caller: callerNumber, dialed: dialedNumber, org_id: orgId, call_sid: callSid, duration_sec: durationSec, agent_id: raw.agent_id || null, received_at: new Date().toISOString() } }];

