  "messages": [{"role": "user", "content": "Direction: {{ $json.direction }}. Duration: {{ $json.duration_sec }}s.\n\nTranscript:\n{{ $json.transcript }}\n\nReturn strict JSON only."}]
}

parameters.jsCode:
const r = items[0].json;
const text = (r.content && r.content[0] && r.content[0].text) || '{}';
const s = text.indexOf('{'), e = text.lastIndexOf('}');
let parsed;
try { parsed = JSON.parse(text.slice(s, e+1)); } catch(_) { parsed = { intent_score: 3, service_type: 'unknown', timeline: 'unknown', suggested_action: 'nurture', summary: 'parse_failed' }; }
const call = $('Normalize Call Payload').first().json;
return [{ json: { ...call, lead: parsed } }];

